-- Seed: ข้อมูล SAP จริงจาก Excel (PO / GR / A/P / การจ่าย)
-- ระบบ ERP ศูนย์การแพทย์ธรรมศาสตร์ — โปรเจกต์ hkqyeeonfyzlbnimztuz
-- วิธีใช้: รัน supabase-schema.sql ก่อน แล้วจึงรันไฟล์นี้ใน SQL Editor
-- (ชุดข้อมูลตัวอย่างสำหรับทดสอบ: PO 1001 · A/P 410 · การจ่าย 400)
-- ============================================================

create table if not exists public.sap_po (
  doc text primary key, pf text, post text, deliv text, vn text, vc text,
  dept text, dn text, who text, val numeric, qty numeric, open numeric, ln int,
  tr text, gd int, ap int, paid int, od int, od_days int, exp text, plan text, fy text,
  grl jsonb default '[]'::jsonb
);
create table if not exists public.sap_ap (
  doc text primary key, post text, vn text, vc text, dept text, dn text,
  val numeric, paid boolean, pay_date text, pay_doc text, method text,
  base text, exp text, plan text
);
create table if not exists public.sap_payment (
  doc text primary key, series text, post text, due text, vn text, vc text,
  total numeric, method text, inv_count int, purpose text
);
alter table public.sap_po enable row level security;
alter table public.sap_ap enable row level security;
alter table public.sap_payment enable row level security;
drop policy if exists "anon all po" on public.sap_po;
create policy "anon all po" on public.sap_po for all to anon using (true) with check (true);
drop policy if exists "anon all ap" on public.sap_ap;
create policy "anon all ap" on public.sap_ap for all to anon using (true) with check (true);
drop policy if exists "anon all pay" on public.sap_payment;
create policy "anon all pay" on public.sap_payment for all to anon using (true) with check (true);

truncate public.sap_po, public.sap_ap, public.sap_payment;














